def most_common_word(s):
    words = s.lower().split()
    counts = {}

    # Count occurrences of each word
    for word in words:
        if word in counts:
            counts[word] += 1
        else:
            counts[word] = 1

    # Find the word with the highest count
    max_count = max(counts.values())
    common_words = [word for word, count in counts.items() if count == max_count]

    # Return the alphabetically first word with the highest count
    return min(common_words) if common_words else ''
